import { describe, expect, test } from "bun:test";
import { handle } from "../src/handler";

describe("handler", () => {
  test("returns service info on root", () => {
    const res = handle(new Request("http://localhost/"), {} as any);
    expect(res.status).toBe(200);
  });

  test("returns health status on /health", async () => {
    const res = handle(new Request("http://localhost/health"), {} as any);
    expect(res.status).toBe(200);
    expect(await res.json()).toEqual({ status: "ok" });
  });

  test("returns 404 for unknown path", () => {
    const res = handle(new Request("http://localhost/missing"), {} as any);
    expect(res.status).toBe(404);
  });
});
